import{_ as t,o as a,c as o,a2 as s}from"./chunks/framework.BYlK8ftn.js";const u=JSON.parse('{"title":"Economy","description":"","frontmatter":{},"headers":[],"relativePath":"guide/economy.md","filePath":"guide/economy.md","lastUpdated":1782025478000}'),i={name:"guide/economy.md"};function n(d,e,r,c,l,h){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="economy" tabindex="-1">Economy <a class="header-anchor" href="#economy" aria-label="Permalink to &quot;Economy&quot;">​</a></h1><p>E4.4 adds the economy core: a <strong>currency</strong> and pure <strong>buy/sell transactions</strong> layered on the existing inventory model (E3.4). This is the transaction logic only — the merchant / shop UI is a separate, Iris-gated ticket. All of it is pure, engine-agnostic game code in <code>src/game/economy/</code> with a thin Redux seam in <code>src/store/inventorySlice.ts</code>.</p><h2 id="currency-is-the-carried-gold" tabindex="-1">Currency is the carried <code>gold</code> <a class="header-anchor" href="#currency-is-the-carried-gold" aria-label="Permalink to &quot;Currency is the carried \`gold\`&quot;">​</a></h2><p>Money is <strong>gold pieces</strong>, and gold is already a carried good: caravan loot tables (E3.3) drop the <code>gold</code> item straight into the player&#39;s inventory (E3.4). So the currency <em>is</em> the <code>gold</code> stack in the inventory rather than a separate wallet scalar — looted coin is spendable coin, and there is no second balance to keep in sync. As a consequence this ticket needs <strong>no save-schema bump</strong>: the gold balance already persists as part of the inventory snapshot.</p><p><code>src/game/economy/currency.ts</code> is the named seam over that balance:</p><ul><li><code>CURRENCY_ITEM_ID</code> — the item id that doubles as money (<code>&#39;gold&#39;</code>).</li><li><code>getBalance(inv)</code> — current spendable gold (the <code>gold</code> stack count, or <code>0</code>).</li><li><code>canAfford(inv, amount)</code> — whether the balance covers <code>amount</code>.</li><li><code>credit(inv, amount)</code> / <code>debit(inv, amount)</code> — add / remove gold, returning fresh state. <code>debit</code> clamps at zero (never overdraws); both ignore non-positive / non-finite amounts.</li></ul><p>Callers should use these instead of reaching into <code>counts.gold</code> by hand.</p><h2 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h2><p>Each item in the catalog (<code>src/game/economy/items.ts</code>) carries a base market <code>value</code> in gold pieces — the <strong>buy price</strong> of one unit. Merchants buy goods back at a markdown (<code>SELL_RATE</code>, currently <code>0.5</code>), floored to whole gold and never below <code>1</code> for a good worth anything. A <code>value</code> of <code>0</code> marks a good as not tradeable.</p><table tabindex="0"><thead><tr><th>Item</th><th>Value (buy)</th><th>Sell (×0.5)</th></tr></thead><tbody><tr><td>Gold (currency)</td><td>1</td><td>— (never traded)</td></tr><tr><td>Bandage</td><td>15</td><td>7</td></tr><tr><td>Grain</td><td>8</td><td>4</td></tr><tr><td>Bolt of Cloth</td><td>25</td><td>12</td></tr><tr><td>Looted Blade</td><td>60</td><td>30</td></tr></tbody></table><p>The <strong>Bandage</strong> is also the dismemberment counterplay consumable (P7.2): it drops from caravans and can be spent to stop bleeding from a severed limb — see <a href="./health-system#dismemberment-counterplay-p72">health-system.md</a>.</p><p>Price helpers in <code>src/game/economy/transactions.ts</code>: <code>itemValue(id)</code>, <code>buyPrice(id, qty)</code>, <code>unitSellPrice(id)</code>, <code>sellPrice(id, qty)</code>, and <code>isTradeable(id)</code> (false for the currency and for unknown / zero-value goods).</p><h2 id="transactions" tabindex="-1">Transactions <a class="header-anchor" href="#transactions" aria-label="Permalink to &quot;Transactions&quot;">​</a></h2><p><code>buy</code> and <code>sell</code> are pure functions over the inventory; nothing mutates the input. Each returns a discriminated result:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> result</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> buy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(inventory, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;cloth&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (result.ok) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  result.inventory </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// new state: gold debited, goods added</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  result.total     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// gold that changed hands</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  result.balance   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// gold balance after the trade</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  result.reason </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// why it failed (see below)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ul><li><code>buy(inv, itemId, qty=1)</code> — debits the gold cost and adds the goods.</li><li><code>sell(inv, itemId, qty=1)</code> — removes the goods and credits the marked-down gold.</li></ul><p>Failure reasons (<code>TransactionFailureReason</code>), returned without touching state:</p><table tabindex="0"><thead><tr><th>Reason</th><th>When</th></tr></thead><tbody><tr><td><code>invalid-quantity</code></td><td>quantity is zero or negative</td></tr><tr><td><code>unknown-item</code></td><td>the id is not in the catalog</td></tr><tr><td><code>not-tradeable</code></td><td>the id is the currency or a zero-value good</td></tr><tr><td><code>insufficient-funds</code></td><td>buy: balance does not cover the total</td></tr><tr><td><code>insufficient-stock</code></td><td>sell: the player does not carry that many</td></tr></tbody></table><p>A buy → sell round-trip returns the goods to the merchant at a loss equal to the markdown — there is no money pump.</p><h2 id="store-bridge" tabindex="-1">Store bridge <a class="header-anchor" href="#store-bridge" aria-label="Permalink to &quot;Store bridge&quot;">​</a></h2><p><code>src/store/inventorySlice.ts</code> exposes the economy on the existing inventory slice (currency lives there, so trades stay inside one state):</p><ul><li><code>buyItem({ itemId, quantity? })</code> — applies <code>buy</code>; <strong>no-op</strong> if the trade fails.</li><li><code>sellItem({ itemId, quantity? })</code> — applies <code>sell</code>; <strong>no-op</strong> if the trade fails.</li><li><code>selectGold(state)</code> — current gold balance.</li><li><code>selectInventory(state)</code> — the whole inventory state.</li></ul><p>The reducers no-op on failure (like the other inventory ops). The shop UI ticket can call the pure <code>buy</code> / <code>sell</code> directly to validate and surface the failure reason to the player <em>before</em> dispatching, and can dispatch <code>recordPurchase</code> (see <a href="./character-progression">character-progression.md</a>) to award trade-skill XP on a successful buy.</p>`,23)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
